There is one thing that I don't fully understand though: why does the port's extra-patch-clang_lib_Driver_ToolChains_Clang.cpp *remove* the check for FreeBSD >= 13?  E.g. it is just:

--- clang/lib/Driver/ToolChains/Clang.cpp.orig  2021-08-11 19:51:00.122735000 +0200
+++ clang/lib/Driver/ToolChains/Clang.cpp       2021-08-11 19:51:24.346107000 +0200
@@ -1921,8 +1921,7 @@
   if (T.isOSBinFormatELF()) {
     switch (getToolChain().getArch()) {
     case llvm::Triple::ppc64: {
-      if ((T.isOSFreeBSD() && T.getOSMajorVersion() >= 13) ||
-          T.isOSOpenBSD() || T.isMusl())
+      if (T.isOSFreeBSD() || T.isOSOpenBSD() || T.isMusl())
         ABIName = "elfv2";
       else
         ABIName = "elfv1";

The other patch, patch-lib_Target_PowerPC_PPCTargetMachine.cpp, does exactly the reverse! I.e. it uses elfv1 for FreeBSD < 13, and elfv2 for >= 13.

Is the Clang.cpp patch actually needed? I think you might get in trouble if you *compile* stuff for elfv2 and then use LTO at link time where it selects elfv1?

Brooks, any idea where that one came from?

Note that Justin's original change to clang/lib/Basic/Targets/PPC.h also checked the OS version and use elfv1 for < 13, elfv2 for >= 13:

--- a/contrib/llvm-project/clang/lib/Basic/Targets/PPC.h
+++ b/contrib/llvm-project/clang/lib/Basic/Targets/PPC.h
@@ -375,12 +375,29 @@ class LLVM_LIBRARY_VISIBILITY PPC64TargetInfo : public PPCTargetInfo {
     IntMaxType = SignedLong;
     Int64Type = SignedLong;

+    if (Triple.getEnvironment() != llvm::Triple::UnknownEnvironment) {
+      switch (Triple.getEnvironment()){
+        case llvm::Triple::ELFv1:
+          ABI = "elfv1";
+          break;
+       default:
+          ABI = "elfv2";
+       break;
+      }
+    } else {
+      if ((Triple.getOS() == llvm::Triple::FreeBSD) &&
+             (Triple.getOSMajorVersion() < 13)) {
+        ABI = "elfv1";
+      } else {
+        ABI = "elfv2";
+      }
+    }
+
+
     if ((Triple.getArch() == llvm::Triple::ppc64le)) {
       resetDataLayout("e-m:e-i64:64-n32:64");
-      ABI = "elfv2";
     } else {
       resetDataLayout("E-m:e-i64:64-n32:64");
-      ABI = Triple.getEnvironment() == llvm::Triple::ELFv2 ? "elfv2" : "elfv1";
     }

     if (Triple.getOS() == llvm::Triple::AIX)

but this block of code doesn't exist anymore as-is, it has been refactored.
